#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e6+5;
int son[maxn][26],idx;
vector<pair<int,int>> g[maxn];
void insert(int r,int v,string &s) {
	int p=0;
	for(auto e:s) {
		int c=e-'a';
		if(!son[p][c]) {
			son[p][c]=++idx;
		}
		p=son[p][c];
		g[p].emplace_back(r,v);
	}
}
void build() {
	for(int i=1; i<=idx; i++) {
		if(!g[i].size()) {
			continue;
		}
		sort(g[i].begin(),g[i].end());
		for(int j=1; j<g[i].size(); j++) {
			g[i][j].second+=g[i][j-1].second;
		}
	}
}
int query(int d,string &s) {
	int p=0;
	for(auto e:s) {
		int c=e-'a';
		if(!son[p][c]) {
			return 0;
		}
		p=son[p][c];
	}
	if(!g[p].size()) {
		return 0;
	}
	auto it=upper_bound(g[p].begin(),g[p].end(),make_pair(d,LLONG_MAX));
	if(it==g[p].begin()) {
		return 0;
	}
	return prev(it)->second;
}
int n,m;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		int r,v;
		string s;
		cin>>r>>v>>s;
		insert(r,v,s);
	}
	build();
	for(int i=1;i<=m;i++){
		int d;
		string q;
		cin>>d>>q;
		cout<<query(d,q)<<"\n";
	}
	return 0;
}
